//! # neurosurf-rs
//!
//! A comprehensive Rust implementation of surface-based neuroimaging data structures and algorithms.
//! This crate provides high-performance, memory-safe tools for working with brain surface meshes,
//! including support for various file formats, geometric operations, and analysis algorithms.
//!
//! ## Core Features
//!
//! - **Surface Geometry**: Efficient representation of triangle meshes using the `tri-mesh` crate
//! - **Graph Operations**: Network analysis of surface connectivity via `petgraph`
//! - **File I/O**: Support for FreeSurfer, GIFTI, and NIML formats
//! - **Geometric Operations**: Curvature calculation, smoothing, and remeshing
//! - **Analysis Algorithms**: Searchlight analysis and surface-based statistics
//! - **Parallel Processing**: Multi-threaded operations using `rayon`
//!
//! ## Quick Start
//!
//! ```rust
//! use neurosurf_rs::geometry::SurfaceGeometry;
//! use neurosurf_rs::io::read_surface;
//!
//! # fn main() -> Result<(), Box<dyn std::error::Error>> {
//! // Load a surface from file
//! let surface = read_surface("path/to/surface.gii")?;
//!
//! // Access mesh properties
//! let vertex_count = surface.vertex_count();
//! let face_count = surface.face_count();
//!
//! // Perform geometric operations
//! let curvature = surface.mean_curvature()?;
//! let smoothed = surface.smooth_laplacian(0.1, 10)?;
//! # Ok(())
//! # }
//! ```
//!
//! ## Module Organization
//!
//! - [`geometry`] - Core surface geometry and mesh operations
//! - [`surface`] - Neuroimaging surface data structures
//! - [`io`] - File format readers and writers
//! - [`graph`] - Graph-based operations and connectivity
//! - [`analysis`] - Analysis algorithms and statistical tools
//! - [`visualization`] - Export utilities for visualization

pub mod error;
pub mod geometry;
pub mod surface;
pub mod io;
pub mod graph;
pub mod analysis;
pub mod visualization;

// Re-export commonly used types
pub use error::{NeuroSurfError, Result};
pub use geometry::SurfaceGeometry;
pub use surface::{NeuroSurface, SurfaceData};

#[cfg(feature = "parallel")]
pub use rayon;

