//! Error types for the neurosurf-rs crate.

use thiserror::Error;

/// The main error type for neurosurf-rs operations.
#[derive(Error, Debug)]
pub enum NeuroSurfError {
    /// File I/O errors
    #[error("I/O error: {0}")]
    Io(#[from] std::io::Error),

    /// File format parsing errors
    #[error("Parse error: {0}")]
    Parse(String),

    /// Invalid surface geometry
    #[error("Invalid geometry: {0}")]
    InvalidGeometry(String),

    /// Invalid surface data
    #[error("Invalid surface data: {0}")]
    InvalidData(String),

    /// Graph operation errors
    #[error("Graph error: {0}")]
    Graph(String),

    /// Dimension mismatch errors
    #[error("Dimension mismatch: expected {expected}, got {actual}")]
    DimensionMismatch { expected: usize, actual: usize },

    /// Index out of bounds
    #[error("Index out of bounds: {index} >= {length}")]
    IndexOutOfBounds { index: usize, length: usize },

    /// Unsupported file format
    #[error("Unsupported file format: {format}")]
    UnsupportedFormat { format: String },

    /// Feature not available
    #[error("Feature '{feature}' not available. Enable the '{feature}' feature flag.")]
    FeatureNotAvailable { feature: String },

    /// Numerical computation errors
    #[error("Numerical error: {0}")]
    Numerical(String),

    /// Memory allocation errors
    #[error("Memory allocation error: {0}")]
    Memory(String),

    /// Generic error with custom message
    #[error("{0}")]
    Custom(String),
}

/// Convenience result type for neurosurf-rs operations.
pub type Result<T> = std::result::Result<T, NeuroSurfError>;

impl NeuroSurfError {
    /// Create a new parse error.
    pub fn parse_error(msg: impl Into<String>) -> Self {
        Self::Parse(msg.into())
    }

    /// Create a new invalid geometry error.
    pub fn invalid_geometry(msg: impl Into<String>) -> Self {
        Self::InvalidGeometry(msg.into())
    }

    /// Create a new invalid data error.
    pub fn invalid_data(msg: impl Into<String>) -> Self {
        Self::InvalidData(msg.into())
    }

    /// Create a new graph error.
    pub fn graph_error(msg: impl Into<String>) -> Self {
        Self::Graph(msg.into())
    }

    /// Create a new dimension mismatch error.
    pub fn dimension_mismatch(expected: usize, actual: usize) -> Self {
        Self::DimensionMismatch { expected, actual }
    }

    /// Create a new index out of bounds error.
    pub fn index_out_of_bounds(index: usize, length: usize) -> Self {
        Self::IndexOutOfBounds { index, length }
    }

    /// Create a new unsupported format error.
    pub fn unsupported_format(format: impl Into<String>) -> Self {
        Self::UnsupportedFormat {
            format: format.into(),
        }
    }

    /// Create a new feature not available error.
    pub fn feature_not_available(feature: impl Into<String>) -> Self {
        Self::FeatureNotAvailable {
            feature: feature.into(),
        }
    }

    /// Create a new numerical error.
    pub fn numerical_error(msg: impl Into<String>) -> Self {
        Self::Numerical(msg.into())
    }

    /// Create a new memory error.
    pub fn memory_error(msg: impl Into<String>) -> Self {
        Self::Memory(msg.into())
    }

    /// Create a new custom error.
    pub fn custom(msg: impl Into<String>) -> Self {
        Self::Custom(msg.into())
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_error_creation() {
        let err = NeuroSurfError::parse_error("test error");
        assert!(matches!(err, NeuroSurfError::Parse(_)));
    }

    #[test]
    fn test_dimension_mismatch() {
        let err = NeuroSurfError::dimension_mismatch(3, 4);
        assert!(matches!(err, NeuroSurfError::DimensionMismatch { expected: 3, actual: 4 }));
    }

    #[test]
    fn test_error_display() {
        let err = NeuroSurfError::custom("test message");
        assert_eq!(format!("{}", err), "test message");
    }
}

