//! Surface geometry types and operations.
//!
//! This module provides the core geometric representation of brain surfaces,
//! including mesh structures, vertex operations, and geometric computations.

pub mod surface;
pub mod mesh_ops;
pub mod curvature;

pub use surface::SurfaceGeometry;
pub use mesh_ops::{MeshOperations, MeshBuilder};
pub use curvature::{CurvatureType, compute_curvature};

use crate::error::{NeuroSurfError, Result};
use nalgebra::{Point3, Vector3};
use ndarray::{Array1, Array2};

/// Hemisphere designation for brain surfaces.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum Hemisphere {
    /// Left hemisphere
    Left,
    /// Right hemisphere
    Right,
    /// Both hemispheres or hemisphere-independent
    Both,
    /// Unknown hemisphere
    Unknown,
}

impl Hemisphere {
    /// Parse hemisphere from string representation.
    pub fn from_str(s: &str) -> Self {
        match s.to_lowercase().as_str() {
            "left" | "lh" | "l" => Self::Left,
            "right" | "rh" | "r" => Self::Right,
            "both" | "bilateral" => Self::Both,
            _ => Self::Unknown,
        }
    }

    /// Convert to string representation.
    pub fn as_str(&self) -> &'static str {
        match self {
            Self::Left => "left",
            Self::Right => "right",
            Self::Both => "both",
            Self::Unknown => "unknown",
        }
    }
}

/// Surface type classification.
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub enum SurfaceType {
    /// White matter surface
    White,
    /// Pial surface
    Pial,
    /// Inflated surface
    Inflated,
    /// Spherical surface
    Spherical,
    /// Flattened surface
    Flat,
    /// Smoothed white matter
    SmoothWM,
    /// Custom surface type
    Custom(String),
}

impl SurfaceType {
    /// Parse surface type from string.
    pub fn from_str(s: &str) -> Self {
        match s.to_lowercase().as_str() {
            "white" => Self::White,
            "pial" => Self::Pial,
            "inflated" => Self::Inflated,
            "spherical" | "sphere" => Self::Spherical,
            "flat" => Self::Flat,
            "smoothwm" => Self::SmoothWM,
            _ => Self::Custom(s.to_string()),
        }
    }

    /// Convert to string representation.
    pub fn as_str(&self) -> &str {
        match self {
            Self::White => "white",
            Self::Pial => "pial",
            Self::Inflated => "inflated",
            Self::Spherical => "spherical",
            Self::Flat => "flat",
            Self::SmoothWM => "smoothwm",
            Self::Custom(s) => s,
        }
    }
}

/// Common geometric operations for surfaces.
pub trait GeometricOperations {
    /// Calculate surface area.
    fn surface_area(&self) -> Result<f64>;

    /// Calculate vertex normals.
    fn vertex_normals(&self) -> Result<Array2<f64>>;

    /// Calculate face normals.
    fn face_normals(&self) -> Result<Array2<f64>>;

    /// Calculate face areas.
    fn face_areas(&self) -> Result<Array1<f64>>;

    /// Get bounding box as (min, max) coordinates.
    fn bounding_box(&self) -> Result<(Point3<f64>, Point3<f64>)>;

    /// Calculate centroid.
    fn centroid(&self) -> Result<Point3<f64>>;
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_hemisphere_parsing() {
        assert_eq!(Hemisphere::from_str("left"), Hemisphere::Left);
        assert_eq!(Hemisphere::from_str("lh"), Hemisphere::Left);
        assert_eq!(Hemisphere::from_str("RIGHT"), Hemisphere::Right);
        assert_eq!(Hemisphere::from_str("unknown"), Hemisphere::Unknown);
    }

    #[test]
    fn test_surface_type_parsing() {
        assert_eq!(SurfaceType::from_str("white"), SurfaceType::White);
        assert_eq!(SurfaceType::from_str("PIAL"), SurfaceType::Pial);
        assert_eq!(SurfaceType::from_str("custom"), SurfaceType::Custom("custom".to_string()));
    }
}

