//! File I/O support for various neuroimaging formats.

pub mod freesurfer;
pub mod gifti;
pub mod niml;

use crate::error::{NeuroSurfError, Result};
use crate::geometry::SurfaceGeometry;
use crate::surface::NeuroSurface;
use std::path::Path;

/// Read a surface from a file, automatically detecting the format.
pub fn read_surface<P: AsRef<Path>>(path: P) -> Result<SurfaceGeometry> {
    let path = path.as_ref();
    let extension = path.extension()
        .and_then(|ext| ext.to_str())
        .unwrap_or("");

    match extension {
        "asc" => freesurfer::read_ascii_surface(path),
        "gii" => {
            #[cfg(feature = "gifti-support")]
            {
                gifti::read_gifti_surface(path)
            }
            #[cfg(not(feature = "gifti-support"))]
            {
                Err(NeuroSurfError::feature_not_available("gifti-support"))
            }
        }
        "dset" => niml::read_niml_surface(path),
        _ => {
            // Try to detect format from file content
            detect_and_read_surface(path)
        }
    }
}

/// Read surface data from a file.
pub fn read_surface_data<P: AsRef<Path>>(path: P) -> Result<Vec<f64>> {
    let path = path.as_ref();
    let extension = path.extension()
        .and_then(|ext| ext.to_str())
        .unwrap_or("");

    match extension {
        "1D" => freesurfer::read_1d_data(path),
        "annot" => freesurfer::read_annotation_data(path),
        "dset" => niml::read_niml_data(path),
        _ => Err(NeuroSurfError::unsupported_format(extension)),
    }
}

/// Detect file format and read surface.
fn detect_and_read_surface<P: AsRef<Path>>(path: P) -> Result<SurfaceGeometry> {
    // TODO: Implement format detection based on file content
    Err(NeuroSurfError::unsupported_format("unknown"))
}

/// Write a surface to a file.
pub fn write_surface<P: AsRef<Path>>(surface: &SurfaceGeometry, path: P) -> Result<()> {
    let path = path.as_ref();
    let extension = path.extension()
        .and_then(|ext| ext.to_str())
        .unwrap_or("");

    match extension {
        "asc" => freesurfer::write_ascii_surface(surface, path),
        "gii" => {
            #[cfg(feature = "gifti-support")]
            {
                gifti::write_gifti_surface(surface, path)
            }
            #[cfg(not(feature = "gifti-support"))]
            {
                Err(NeuroSurfError::feature_not_available("gifti-support"))
            }
        }
        _ => Err(NeuroSurfError::unsupported_format(extension)),
    }
}

/// Write surface data to a file.
pub fn write_surface_data<P: AsRef<Path>>(data: &[f64], path: P) -> Result<()> {
    let path = path.as_ref();
    let extension = path.extension()
        .and_then(|ext| ext.to_str())
        .unwrap_or("");

    match extension {
        "1D" => freesurfer::write_1d_data(data, path),
        _ => Err(NeuroSurfError::unsupported_format(extension)),
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_format_detection() {
        // These tests would require actual test files
        // For now, just test that the functions exist
        assert!(read_surface("test.unknown").is_err());
        assert!(read_surface_data("test.unknown").is_err());
    }
}

