/// Read a FreeSurfer ASCII surface file.
pub fn read_ascii_surface<P: AsRef<Path>>(path: P) -> Result<SurfaceGeometry> {
    let file = File::open(path)?;
    let reader = BufReader::new(file);
    let mut lines = reader.lines();

    // Skip comment lines
    while let Some(line) = lines.next() {
        let line = line?;
        if !line.starts_with('#') {
            // First non-comment line should contain vertex and face counts
            let parts: Vec<&str> = line.split_whitespace().collect();
            if parts.len() != 2 {
                return Err(NeuroSurfError::parse_error("Invalid vertex/face count line"));
            }

