                .map_err(|_| NeuroSurfError::parse_error("Invalid vertex count"))?;
            let face_count: usize = parts[1].parse()
                .map_err(|_| NeuroSurfError::parse_error("Invalid face count"))?;

            // Read vertices
            let mut vertices = Array2::zeros((vertex_count, 3));
            for i in 0..vertex_count {
                let line = lines.next()
                    .ok_or_else(|| NeuroSurfError::parse_error("Unexpected end of file"))?;
                let line = line?;
                let coords: Vec<f64> = line.split_whitespace()
                    .take(3)
                    .map(|s| s.parse::<f64>())
                    .collect::<std::result::Result<Vec<_>, _>>()
                    .map_err(|_| NeuroSurfError::parse_error("Invalid vertex coordinates"))?;

                if coords.len() != 3 {
                    return Err(NeuroSurfError::parse_error("Invalid vertex format"));
                }

                vertices[[i, 0]] = coords[0];
                vertices[[i, 1]] = coords[1];
                vertices[[i, 2]] = coords[2];
            }

            // Read faces
            let mut faces = Array2::zeros((face_count, 3));
            for i in 0..face_count {
                let line = lines.next()
                    .ok_or_else(|| NeuroSurfError::parse_error("Unexpected end of file"))?;
                let line = line?;
                let indices: Vec<usize> = line.split_whitespace()
                    .take(3)
                    .map(|s| s.parse::<usize>())
                    .collect::<std::result::Result<Vec<_>, _>>()
                    .map_err(|_| NeuroSurfError::parse_error("Invalid face indices"))?;

                if indices.len() != 3 {
                    return Err(NeuroSurfError::parse_error("Invalid face format"));
                }

                faces[[i, 0]] = indices[0];
                faces[[i, 1]] = indices[1];
                faces[[i, 2]] = indices[2];
            }

            return SurfaceGeometry::new(
                vertices,
                faces,
                Hemisphere::Unknown,
                SurfaceType::Custom("ascii".to_string()),
            );
        }
    }

    Err(NeuroSurfError::parse_error("No valid data found in file"))
}

/// Read a FreeSurfer binary surface file.
pub fn read_binary_surface<P: AsRef<Path>>(path: P) -> Result<SurfaceGeometry> {
    let mut file = File::open(path)?;

    // Read magic number
    let mut magic = [0u8; 3];
    file.read_exact(&mut magic)?;

    // Skip newline
    let mut newline = [0u8; 1];
    file.read_exact(&mut newline)?;

    // Read comment line
    let mut comment = [0u8; 80];
    file.read_exact(&mut comment)?;

    // Read vertex and face counts
    let vertex_count = file.read_u32::<BigEndian>()? as usize;
    let face_count = file.read_u32::<BigEndian>()? as usize;

    // Read vertices
    let mut vertices = Array2::zeros((vertex_count, 3));
    for i in 0..vertex_count {
        let x = file.read_f32::<BigEndian>()? as f64;
        let y = file.read_f32::<BigEndian>()? as f64;
        let z = file.read_f32::<BigEndian>()? as f64;

        vertices[[i, 0]] = x;
        vertices[[i, 1]] = y;
        vertices[[i, 2]] = z;
    }

    // Read faces
    let mut faces = Array2::zeros((face_count, 3));
    for i in 0..face_count {
        let v1 = file.read_u32::<BigEndian>()? as usize;
        let v2 = file.read_u32::<BigEndian>()? as usize;
        let v3 = file.read_u32::<BigEndian>()? as usize;

        faces[[i, 0]] = v1;
        faces[[i, 1]] = v2;
        faces[[i, 2]] = v3;
    }

    SurfaceGeometry::new(
        vertices,
        faces,
        Hemisphere::Unknown,
        SurfaceType::Custom("binary".to_string()),
    )
}

/// Write a FreeSurfer ASCII surface file.
pub fn write_ascii_surface<P: AsRef<Path>>(surface: &SurfaceGeometry, path: P) -> Result<()> {
    let file = File::create(path)?;
    let mut writer = BufWriter::new(file);

    // Write header
    writeln!(writer, "# ASCII surface file")?;
    writeln!(writer, "{} {}", surface.vertex_count(), surface.face_count())?;

    // Write vertices
    let vertices = surface.vertices()?;
    for i in 0..vertices.nrows() {
        writeln!(writer, "{} {} {}", vertices[[i, 0]], vertices[[i, 1]], vertices[[i, 2]])?;
    }

    // Write faces
    let faces = surface.faces()?;
    for i in 0..faces.nrows() {
        writeln!(writer, "{} {} {}", faces[[i, 0]], faces[[i, 1]], faces[[i, 2]])?;
    }

    Ok(())
}

