//! Searchlight analysis for surface-based neuroimaging.

use crate::error::{NeuroSurfError, Result};
use crate::geometry::SurfaceGeometry;
use crate::graph::neighborhood::NeighborhoodGraph;
use ndarray::Array1;
#[cfg(feature = "parallel")]
use rayon::prelude::*;
use std::collections::HashSet;

/// Searchlight iterator for surface analysis.
pub struct SurfaceSearchlight {
    /// The surface geometry
    surface: SurfaceGeometry,
    /// Searchlight radius
    radius: f64,
    /// Node indices to search
    nodes: Vec<usize>,
    /// Current position
    current: usize,
}

impl SurfaceSearchlight {
    /// Create a new surface searchlight.
    pub fn new(surface: SurfaceGeometry, radius: f64) -> Self {
        let nodes: Vec<usize> = (0..surface.vertex_count()).collect();
        Self {
            surface,
            radius,
            nodes,
            current: 0,
        }
    }

    /// Create a searchlight with specific nodes.
    pub fn with_nodes(surface: SurfaceGeometry, radius: f64, nodes: Vec<usize>) -> Self {
        Self {
            surface,
            radius,
            nodes,
            current: 0,
        }
    }

    /// Get the next searchlight region.
    pub fn next(&mut self) -> Option<SearchlightRegion> {
        if self.current >= self.nodes.len() {
            return None;
        }

        let center = self.nodes[self.current];
        self.current += 1;

        // TODO: Implement actual neighborhood finding
        let neighbors = vec![center]; // Placeholder

        Some(SearchlightRegion {
            center,
            nodes: neighbors,
            radius: self.radius,
        })
    }

    /// Get the progress (0.0 to 1.0).
    pub fn progress(&self) -> f64 {
        self.current as f64 / self.nodes.len() as f64
    }
}

/// Random searchlight iterator.
pub struct RandomSurfaceSearchlight {
    /// The surface geometry
    surface: SurfaceGeometry,
    /// Searchlight radius
    radius: f64,
    /// Available nodes
    available: HashSet<usize>,
    /// Used nodes
    used: HashSet<usize>,
}

impl RandomSurfaceSearchlight {
    /// Create a new random surface searchlight.
    pub fn new(surface: SurfaceGeometry, radius: f64) -> Self {
        let available: HashSet<usize> = (0..surface.vertex_count()).collect();
        Self {
            surface,
            radius,
            available,
            used: HashSet::new(),
        }
    }

    /// Get the next random searchlight region.
    pub fn next(&mut self) -> Option<SearchlightRegion> {
        if self.available.is_empty() {
            return None;
        }

        // TODO: Implement proper random sampling
        let center = *self.available.iter().next().unwrap();
        self.available.remove(&center);

        // TODO: Implement actual neighborhood finding
        let neighbors = vec![center]; // Placeholder

        // Mark neighbors as used
        for &node in &neighbors {
            self.used.insert(node);
            self.available.remove(&node);
        }

        Some(SearchlightRegion {
            center,
            nodes: neighbors,
            radius: self.radius,
        })
    }

    /// Get the progress (0.0 to 1.0).
    pub fn progress(&self) -> f64 {
        let total = self.surface.vertex_count();
        let used = self.used.len();
        used as f64 / total as f64
    }
}

/// A searchlight region on the surface.
#[derive(Debug, Clone)]
pub struct SearchlightRegion {
    /// Center vertex of the searchlight
    pub center: usize,
    /// Vertices in the searchlight region
    pub nodes: Vec<usize>,
    /// Radius of the searchlight
    pub radius: f64,
}

impl SearchlightRegion {
    /// Get the center vertex.
    pub fn center(&self) -> usize {
        self.center
    }

    /// Get the vertices in the region.
    pub fn nodes(&self) -> &[usize] {
        &self.nodes
    }

    /// Get the radius.
    pub fn radius(&self) -> f64 {
        self.radius
    }

    /// Get the number of vertices in the region.
    pub fn len(&self) -> usize {
        self.nodes.len()
    }

    /// Check if the region is empty.
    pub fn is_empty(&self) -> bool {
        self.nodes.is_empty()
    }
}

/// Parallel searchlight analysis.
pub fn parallel_searchlight<F, R>(
    surface: SurfaceGeometry,
    radius: f64,
    analysis_fn: F,
) -> Result<Vec<R>>
where
    F: Fn(&SearchlightRegion) -> Result<R> + Send + Sync,
    R: Send,
{
    let mut searchlight = SurfaceSearchlight::new(surface, radius);
    let mut regions = Vec::new();

    while let Some(region) = searchlight.next() {
        regions.push(region);
    }

    regions
        .into_par_iter()
        .map(|region| analysis_fn(&region))
        .collect()
}

