//! Core surface geometry implementation.

use crate::error::{NeuroSurfError, Result};
use crate::geometry::{GeometricOperations, Hemisphere, SurfaceType};
use nalgebra::{Point3, Vector3};
use ndarray::{Array1, Array2};
use petgraph::Graph;
use serde::{Deserialize, Serialize};
use std::collections::HashMap;
use tri_mesh::mesh::Mesh;

/// Core surface geometry structure representing a brain surface mesh.
///
/// This structure combines a triangle mesh representation with graph connectivity
/// and neuroimaging-specific metadata.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct SurfaceGeometry {
    /// The underlying triangle mesh
    mesh: Mesh,
    /// Graph representation of mesh connectivity
    graph: Graph<usize, f64, petgraph::Undirected>,
    /// Hemisphere designation
    hemisphere: Hemisphere,
    /// Surface type classification
    surface_type: SurfaceType,
    /// Additional metadata
    metadata: HashMap<String, String>,
}

impl SurfaceGeometry {
    /// Create a new SurfaceGeometry from vertices and faces.
    ///
    /// # Arguments
    /// * `vertices` - Array of vertex coordinates (N x 3)
    /// * `faces` - Array of face indices (M x 3)
    /// * `hemisphere` - Hemisphere designation
    /// * `surface_type` - Surface type classification
    ///
    /// # Returns
    /// A new SurfaceGeometry instance
    pub fn new(
        vertices: Array2<f64>,
        faces: Array2<usize>,
        hemisphere: Hemisphere,
        surface_type: SurfaceType,
    ) -> Result<Self> {
        // Validate input dimensions
        if vertices.ncols() != 3 {
            return Err(NeuroSurfError::dimension_mismatch(3, vertices.ncols()));
        }
        if faces.ncols() != 3 {
            return Err(NeuroSurfError::dimension_mismatch(3, faces.ncols()));
        }

        // Convert to tri-mesh format
        let positions: Vec<f32> = vertices
            .iter()
            .map(|&v| v as f32)
            .collect();

        let indices: Vec<u32> = faces
            .iter()
            .map(|&idx| idx as u32)
            .collect();

        // Build mesh
        let mesh = Mesh::new(indices, positions, Vec::new())
            .map_err(|e| NeuroSurfError::InvalidGeometry(format!("Mesh creation failed: {:?}", e)))?;

        // Create graph representation
        let graph = Self::build_graph(&mesh)?;

        Ok(Self {
            mesh,
            graph,
            hemisphere,
            surface_type,
            metadata: HashMap::new(),
        })
    }

    /// Get the number of vertices in the surface.
    pub fn vertex_count(&self) -> usize {
        self.mesh.no_vertices()
    }

    /// Get the number of faces in the surface.
    pub fn face_count(&self) -> usize {
        self.mesh.no_faces()
    }

    /// Get the hemisphere designation.
    pub fn hemisphere(&self) -> Hemisphere {
        self.hemisphere
    }

    /// Get the surface type.
    pub fn surface_type(&self) -> &SurfaceType {
        &self.surface_type
    }

    /// Get vertex coordinates as an array.
    pub fn vertices(&self) -> Result<Array2<f64>> {
        let positions = self.mesh.positions_buffer();
        let mut vertices = Array2::zeros((self.vertex_count(), 3));

        for (i, pos) in positions.chunks_exact(3).enumerate() {
            vertices[[i, 0]] = pos[0] as f64;
            vertices[[i, 1]] = pos[1] as f64;
            vertices[[i, 2]] = pos[2] as f64;
        }

        Ok(vertices)
    }

    /// Get face indices as an array.
    pub fn faces(&self) -> Result<Array2<usize>> {
        let indices = self.mesh.indices_buffer();
        let mut faces = Array2::zeros((self.face_count(), 3));

        for (i, face_indices) in indices.chunks_exact(3).enumerate() {
            faces[[i, 0]] = face_indices[0] as usize;
            faces[[i, 1]] = face_indices[1] as usize;
            faces[[i, 2]] = face_indices[2] as usize;
        }

        Ok(faces)
    }

    /// Get the graph representation of the mesh.
    pub fn graph(&self) -> &Graph<usize, f64, petgraph::Undirected> {
        &self.graph
    }

    /// Get metadata value by key.
    pub fn get_metadata(&self, key: &str) -> Option<&str> {
        self.metadata.get(key).map(|s| s.as_str())
    }

    /// Set metadata value.
    pub fn set_metadata(&mut self, key: String, value: String) {
        self.metadata.insert(key, value);
    }

    /// Get all metadata.
    pub fn metadata(&self) -> &HashMap<String, String> {
        &self.metadata
    }

    /// Build a graph representation from the mesh.
    fn build_graph(mesh: &Mesh) -> Result<Graph<usize, f64, petgraph::Undirected>> {
        let mut graph = Graph::new_undirected();

        // Add vertices
        let node_indices: Vec<_> = (0..mesh.no_vertices())
            .map(|i| graph.add_node(i))
            .collect();

        // Add edges based on face connectivity
        for face_id in mesh.face_iter() {
            let vertices = mesh.face_vertices(face_id);
            let v1 = vertices[0].index();
            let v2 = vertices[1].index();
            let v3 = vertices[2].index();

            // Add edges between all pairs of vertices in the face
            graph.add_edge(node_indices[v1], node_indices[v2], 1.0);
            graph.add_edge(node_indices[v2], node_indices[v3], 1.0);
            graph.add_edge(node_indices[v3], node_indices[v1], 1.0);
        }

        Ok(graph)
    }
}

impl GeometricOperations for SurfaceGeometry {
    fn surface_area(&self) -> Result<f64> {
        let area = self.mesh.face_iter()
            .map(|face_id| {
                let area = self.mesh.face_area(face_id);
                area as f64
            })
            .sum();
        Ok(area)
    }

    fn vertex_normals(&self) -> Result<Array2<f64>> {
        let mut normals = Array2::zeros((self.vertex_count(), 3));

        for vertex_id in self.mesh.vertex_iter() {
            let normal = self.mesh.vertex_normal(vertex_id);
            let idx = vertex_id.index();
            normals[[idx, 0]] = normal.x as f64;
            normals[[idx, 1]] = normal.y as f64;
            normals[[idx, 2]] = normal.z as f64;
        }

        Ok(normals)
    }

    fn face_normals(&self) -> Result<Array2<f64>> {
        let mut normals = Array2::zeros((self.face_count(), 3));

        for face_id in self.mesh.face_iter() {
            let normal = self.mesh.face_normal(face_id);
            let idx = face_id.index();
            normals[[idx, 0]] = normal.x as f64;
            normals[[idx, 1]] = normal.y as f64;
            normals[[idx, 2]] = normal.z as f64;
        }

        Ok(normals)
    }

    fn face_areas(&self) -> Result<Array1<f64>> {
        let mut areas = Array1::zeros(self.face_count());

        for face_id in self.mesh.face_iter() {
            let area = self.mesh.face_area(face_id);
            areas[face_id.index()] = area as f64;
        }

        Ok(areas)
    }

    fn bounding_box(&self) -> Result<(Point3<f64>, Point3<f64>)> {
        let positions = self.mesh.positions_buffer();
        let mut min_coords = [f64::INFINITY; 3];
        let mut max_coords = [f64::NEG_INFINITY; 3];

        for pos in positions.chunks_exact(3) {
            for i in 0..3 {
                let coord = pos[i] as f64;
                min_coords[i] = min_coords[i].min(coord);
                max_coords[i] = max_coords[i].max(coord);
            }
        }

        Ok((
            Point3::new(min_coords[0], min_coords[1], min_coords[2]),
            Point3::new(max_coords[0], max_coords[1], max_coords[2]),
        ))
    }

    fn centroid(&self) -> Result<Point3<f64>> {
        let positions = self.mesh.positions_buffer();
        let mut centroid = [0.0; 3];
        let vertex_count = self.vertex_count();

        for pos in positions.chunks_exact(3) {
            for i in 0..3 {
                centroid[i] += pos[i] as f64;
            }
        }

        for i in 0..3 {
            centroid[i] /= vertex_count as f64;
        }

        Ok(Point3::new(centroid[0], centroid[1], centroid[2]))
    }
}

