use crate::error::{NeuroSurfError, Result};
use crate::geometry::SurfaceGeometry;
use crate::surface::{Surface, SurfaceDataOperations};
use ndarray::{Array1, Array2};
use serde::{Deserialize, Serialize};

/// Core neuroimaging surface with associated data.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct NeuroSurface {
    /// The surface geometry
    geometry: SurfaceGeometry,
    /// Node indices for the data
    indices: Vec<usize>,
    /// Data values at each node
    data: Array1<f64>,
}

impl NeuroSurface {
    /// Create a new NeuroSurface.
    pub fn new(geometry: SurfaceGeometry, indices: Vec<usize>, data: Array1<f64>) -> Result<Self> {
        // Validate that indices and data have the same length
        if indices.len() != data.len() {
            return Err(NeuroSurfError::dimension_mismatch(indices.len(), data.len()));
        }

        // Validate that all indices are within bounds
        let max_vertex = geometry.vertex_count();
        for &idx in &indices {
            if idx >= max_vertex {
                return Err(NeuroSurfError::index_out_of_bounds(idx, max_vertex));
            }
        }

        Ok(Self {
            geometry,
            indices,
            data,
        })
    }

    /// Get a reference to the data array.
    pub fn data(&self) -> &Array1<f64> {
        &self.data
    }

    /// Get a mutable reference to the data array.
    pub fn data_mut(&mut self) -> &mut Array1<f64> {
        &mut self.data
    }

    /// Get the indices.
    pub fn indices(&self) -> &[usize] {
        &self.indices
    }

    /// Map values to a new surface with the same geometry.
    pub fn map_values<F>(&self, f: F) -> Result<Self>
    where
        F: Fn(f64) -> f64,
    {
        let new_data = self.data.map(f);
        Ok(Self {
            geometry: self.geometry.clone(),
            indices: self.indices.clone(),
            data: new_data,
        })
    }

    /// Apply a threshold to the surface data.
    pub fn threshold(&self, threshold: f64) -> Result<Self> {
        let mask: Vec<usize> = self.data
            .iter()
            .enumerate()
            .filter(|(_, &value)| value >= threshold)
            .map(|(i, _)| i)
            .collect();

        let new_indices: Vec<usize> = mask.iter().map(|&i| self.indices[i]).collect();
        let new_data = Array1::from_vec(
            mask.iter().map(|&i| self.data[i]).collect()
        );

        Self::new(self.geometry.clone(), new_indices, new_data)
    }
}

