    fn geometry(&self) -> &SurfaceGeometry {
        &self.geometry
    }

    fn hemisphere(&self) -> crate::geometry::Hemisphere {
        self.geometry.hemisphere()
    }

    fn surface_type(&self) -> &crate::geometry::SurfaceType {
        self.geometry.surface_type()
    }
}

