        &self.indices
    }

    fn values(&self) -> &Array1<f64> {
        &self.data
    }

    fn len(&self) -> usize {
        self.data.len()
    }

    fn subset(&self, indices: &[usize]) -> Result<Box<dyn SurfaceDataOperations>> {
        let new_indices: Vec<usize> = indices.iter().map(|&i| self.indices[i]).collect();
        let new_data = Array1::from_vec(
            indices.iter().map(|&i| self.data[i]).collect()
        );

        let subset = NeuroSurface::new(self.geometry.clone(), new_indices, new_data)?;
        Ok(Box::new(subset))
    }
}

