//! Region of interest surface structures.

use crate::error::{NeuroSurfError, Result};
use crate::geometry::SurfaceGeometry;
use crate::surface::{Surface, SurfaceDataOperations};
use ndarray::{Array1, Array2};
use serde::{Deserialize, Serialize};

/// Region of interest on a surface.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ROISurface {
    /// The parent surface geometry
    geometry: SurfaceGeometry,
    /// Data values for the ROI
    data: Array1<f64>,
    /// Coordinates of ROI vertices
    coords: Array2<f64>,
    /// Indices into the parent surface
    indices: Vec<usize>,
}

impl ROISurface {
    /// Create a new ROI surface.
    pub fn new(
        geometry: SurfaceGeometry,
        data: Array1<f64>,
        coords: Array2<f64>,
        indices: Vec<usize>,
    ) -> Result<Self> {
        // Validate dimensions
        if coords.ncols() != 3 {
            return Err(NeuroSurfError::dimension_mismatch(3, coords.ncols()));
        }

        if coords.nrows() != indices.len() {
            return Err(NeuroSurfError::dimension_mismatch(coords.nrows(), indices.len()));
        }

        if data.len() != indices.len() {
            return Err(NeuroSurfError::dimension_mismatch(data.len(), indices.len()));
        }

        Ok(Self {
            geometry,
            data,
            coords,
            indices,
        })
    }

    /// Get the ROI coordinates.
    pub fn coords(&self) -> &Array2<f64> {
        &self.coords
    }

    /// Get the ROI data.
    pub fn data(&self) -> &Array1<f64> {
        &self.data
    }
}

