pub struct SurfaceVector {
    /// The surface geometry
    geometry: SurfaceGeometry,
    /// Node indices for the data
    indices: Vec<usize>,
    /// Data matrix (rows = vertices, columns = measures)
    data: Array2<f64>,
}

impl SurfaceVector {
    /// Create a new surface vector.
    pub fn new(geometry: SurfaceGeometry, indices: Vec<usize>, data: Array2<f64>) -> Result<Self> {
        // Validate dimensions
        if indices.len() != data.nrows() {
            return Err(NeuroSurfError::dimension_mismatch(indices.len(), data.nrows()));
        }

        // Validate indices are within bounds
        let max_vertex = geometry.vertex_count();
        for &idx in &indices {
            if idx >= max_vertex {
                return Err(NeuroSurfError::index_out_of_bounds(idx, max_vertex));
            }
        }

        Ok(Self {
            geometry,
            indices,
            data,
        })
    }

    /// Get the data matrix.
    pub fn data(&self) -> &Array2<f64> {
        &self.data
    }

    /// Get the number of measures (columns).
    pub fn num_measures(&self) -> usize {
        self.data.ncols()
    }

    /// Get data for a specific measure.
    pub fn measure(&self, index: usize) -> Result<Array1<f64>> {
        if index >= self.num_measures() {
            return Err(NeuroSurfError::index_out_of_bounds(index, self.num_measures()));
        }

        Ok(self.data.column(index).to_owned())
    }

    /// Get data for a specific vertex.
    pub fn vertex_data(&self, index: usize) -> Result<Array1<f64>> {
        if index >= self.len() {
            return Err(NeuroSurfError::index_out_of_bounds(index, self.len()));
        }

        Ok(self.data.row(index).to_owned())
    }
}

