//! Visualization utilities and export functions.

use crate::error::Result;
use crate::geometry::SurfaceGeometry;
use crate::surface::{NeuroSurface, Surface};
use ndarray::Array1;
use serde::{Deserialize, Serialize};
use std::path::Path;

/// Color mapping for surface visualization.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ColorMap {
    /// Name of the colormap
    pub name: String,
    /// Color values as RGB triplets
    pub colors: Vec<[f64; 3]>,
    /// Value range for mapping
    pub range: (f64, f64),
}

impl ColorMap {
    /// Create a new colormap.
    pub fn new(name: String, colors: Vec<[f64; 3]>, range: (f64, f64)) -> Self {
        Self { name, colors, range }
    }

    /// Map a value to a color.
    pub fn map_value(&self, value: f64) -> [f64; 3] {
        if self.colors.is_empty() {
            return [0.0, 0.0, 0.0];
        }

        let normalized = (value - self.range.0) / (self.range.1 - self.range.0);
        let normalized = normalized.clamp(0.0, 1.0);

        let index = (normalized * (self.colors.len() - 1) as f64) as usize;
        self.colors[index.min(self.colors.len() - 1)]
    }

    /// Create a viridis colormap.
    pub fn viridis() -> Self {
        // Simplified viridis colors
        let colors = vec![
            [0.267, 0.005, 0.329],
            [0.282, 0.140, 0.458],
            [0.254, 0.265, 0.530],
            [0.206, 0.371, 0.553],
            [0.163, 0.471, 0.558],
            [0.127, 0.566, 0.550],
            [0.134, 0.658, 0.517],
            [0.254, 0.748, 0.440],
            [0.477, 0.821, 0.318],
            [0.741, 0.873, 0.149],
            [0.993, 0.906, 0.144],
        ];

        Self::new("viridis".to_string(), colors, (0.0, 1.0))
    }

    /// Create a plasma colormap.
    pub fn plasma() -> Self {
        // Simplified plasma colors
        let colors = vec![
            [0.050, 0.030, 0.529],
            [0.287, 0.014, 0.627],
            [0.477, 0.003, 0.658],
            [0.647, 0.039, 0.656],
            [0.801, 0.125, 0.601],
            [0.928, 0.233, 0.489],
            [0.988, 0.407, 0.322],
            [0.978, 0.623, 0.174],
            [0.898, 0.846, 0.273],
            [0.987, 0.991, 0.749],
        ];

        Self::new("plasma".to_string(), colors, (0.0, 1.0))
    }
}

/// Export surface data for visualization.
pub fn export_surface_data(
    surface: &NeuroSurface,
    colormap: &ColorMap,
) -> Result<SurfaceVisualization> {
    let geometry = surface.geometry();
    let vertices = geometry.vertices()?;
    let faces = geometry.faces()?;
    let data = surface.data();

    // Map data values to colors
    let colors: Vec<[f64; 3]> = data.iter()
        .map(|&value| colormap.map_value(value))
        .collect();

    Ok(SurfaceVisualization {
        vertices: vertices.to_vec(),
        faces: faces.to_vec(),
        colors,
        metadata: std::collections::HashMap::new(),
    })
}

/// Surface visualization data.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct SurfaceVisualization {
    /// Vertex coordinates
    pub vertices: Vec<Vec<f64>>,
    /// Face indices
    pub faces: Vec<Vec<usize>>,
    /// Color values for vertices
    pub colors: Vec<[f64; 3]>,
    /// Additional metadata
    pub metadata: std::collections::HashMap<String, String>,
}

impl SurfaceVisualization {
    /// Export to JSON format.
    pub fn to_json(&self) -> Result<String> {
        serde_json::to_string_pretty(self)
            .map_err(|e| crate::error::NeuroSurfError::custom(format!("JSON serialization error: {}", e)))
    }

    /// Export to a file.
    pub fn to_file<P: AsRef<Path>>(&self, path: P) -> Result<()> {
        let json = self.to_json()?;
        std::fs::write(path, json)?;
        Ok(())
    }

    /// Export to OBJ format.
    pub fn to_obj(&self) -> Result<String> {
        let mut obj = String::new();

        // Write vertices
        for vertex in &self.vertices {
            obj.push_str(&format!("v {} {} {}\n", vertex[0], vertex[1], vertex[2]));
        }

        // Write faces (OBJ uses 1-based indexing)
        for face in &self.faces {
            obj.push_str(&format!("f {} {} {}\n", face[0] + 1, face[1] + 1, face[2] + 1));
        }

        Ok(obj)
    }
}

/// Blend two colors with alpha.
pub fn blend_colors(color1: [f64; 3], color2: [f64; 3], alpha: f64) -> [f64; 3] {
    let alpha = alpha.clamp(0.0, 1.0);
    [
        color1[0] * (1.0 - alpha) + color2[0] * alpha,
        color1[1] * (1.0 - alpha) + color2[1] * alpha,
        color1[2] * (1.0 - alpha) + color2[2] * alpha,
    ]
}

/// Apply alpha channel to color.
pub fn apply_alpha(color: [f64; 3], alpha: f64) -> [f64; 4] {
    [color[0], color[1], color[2], alpha.clamp(0.0, 1.0)]
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_colormap_creation() {
        let colormap = ColorMap::viridis();
        assert_eq!(colormap.name, "viridis");
        assert!(!colormap.colors.is_empty());

        let color = colormap.map_value(0.5);
        assert!(color[0] >= 0.0 && color[0] <= 1.0);
        assert!(color[1] >= 0.0 && color[1] <= 1.0);
        assert!(color[2] >= 0.0 && color[2] <= 1.0);
    }

    #[test]
    fn test_color_blending() {
        let color1 = [1.0, 0.0, 0.0]; // Red
        let color2 = [0.0, 1.0, 0.0]; // Green
        let blended = blend_colors(color1, color2, 0.5);

        assert_eq!(blended, [0.5, 0.5, 0.0]);
    }

    #[test]
    fn test_alpha_application() {
        let color = [1.0, 0.5, 0.0];
        let rgba = apply_alpha(color, 0.8);

        assert_eq!(rgba, [1.0, 0.5, 0.0, 0.8]);
    }
}

