fn surface_area(&self) -> Result<f64> {
    let mut total_area = 0.0;

    // Calculate area of each triangle face
    for face_idx in 0..self.face_count() {
        let face = self.faces.row(face_idx);
        let v0_idx = face[0];
        let v1_idx = face[1];
        let v2_idx = face[2];

        // Get the three vertices of the triangle
        let v0 = self.vertices.row(v0_idx);
        let v1 = self.vertices.row(v1_idx);
        let v2 = self.vertices.row(v2_idx);

        // Calculate two edge vectors
        let edge1 = [v1[0] - v0[0], v1[1] - v0[1], v1[2] - v0[2]];
        let edge2 = [v2[0] - v0[0], v2[1] - v0[1], v2[2] - v0[2]];

        // Calculate cross product
        let cross = [
            edge1[1] * edge2[2] - edge1[2] * edge2[1],
            edge1[2] * edge2[0] - edge1[0] * edge2[2],
            edge1[0] * edge2[1] - edge1[1] * edge2[0],
        ];

        // Calculate magnitude of cross product
        let cross_magnitude = (cross[0] * cross[0] + cross[1] * cross[1] + cross[2] * cross[2]).sqrt();

        // Triangle area is half the magnitude of the cross product
        total_area += cross_magnitude * 0.5;
    }

    Ok(total_area)
}

