//! # GIFTI-RS: Rust Implementation of GIFTI File Format
//!
//! This library provides a Rust implementation of the GIFTI
//! (Geometry Format under the Neuroimaging Informatics Technology Initiative)
//! file format used in neuroimaging applications.
//!
//! GIFTI files are XML-based and contain surface data for brain imaging,
//! including vertices, triangles, and associated metadata.
//!
//! ## Features
//!
//! - **XML parsing** for GIFTI files
//! - **Multiple encoding formats**: ASCII, Base64Binary, GZipBase64Binary
//! - **Data types**: UINT8, INT32, UINT32, FLOAT32  
//! - **Surface processing**: Triangle mesh operations
//! - **Type-safe**: Leverages Rust's type system
//!
//! ## Quick Start
//!
//! ```rust,no_run
//! use gifti::{read_gifti, write_gifti};
//!
//! // Read a GIFTI file
//! let gifti_data = read_gifti("surface.gii")?;
//! 
//! // Access the data
//! println!("Number of data arrays: {}", gifti_data.num_data_arrays());
//!
//! // Write a GIFTI file
//! write_gifti(&gifti_data, "output.gii")?;
//! # Ok::<(), Box<dyn std::error::Error>>(())
//! ```

pub mod core;
pub mod error;
pub mod io;
pub mod utils;

// Re-export main types and functions
pub use core::{
    DataArray, DataArrayAttributes, DataType, Encoding, Endianness, Gifti, Intent, MetaData,
};
pub use error::{GiftiError, Result};
pub use io::{read_gifti, write_gifti};
pub use utils::{convert_intent, is_gifti, surf_triangles};

// Version information
pub const VERSION: &str = env!("CARGO_PKG_VERSION");
pub const GIFTI_VERSION: &str = "1.0";

