pub fn new_1d(
    data: Vec<f64>,
    data_type: DataType,
    encoding: Encoding,
    intent: Intent,
) -> Result<Self> {
    let len = data.len();
    let dimensions = vec![len];
    let attributes = DataArrayAttributes::new(
        data_type,
