//! GIFTI format support.

use crate::error::{NeuroSurfError, Result};
use crate::geometry::{SurfaceGeometry, Hemisphere, SurfaceType};
use std::path::Path;

#[cfg(feature = "gifti-support")]
use gifti::{read_gifti as gifti_read, write_gifti as gifti_write, Gifti, Intent, DataType};

/// Read a GIFTI surface file.
pub fn read_gifti_surface<P: AsRef<Path>>(path: P) -> Result<SurfaceGeometry> {
    // Check if file exists
    if !path.as_ref().exists() {
        return Err(NeuroSurfError::Io(std::io::Error::new(
            std::io::ErrorKind::NotFound,
            format!("GIFTI file not found: {}", path.as_ref().display())
        )));
    }

    #[cfg(feature = "gifti-support")]
    {
        // Use the gifti-rs library to read the file
        let gifti_data = gifti_read(path).map_err(|e| {
            NeuroSurfError::custom(format!("Failed to read GIFTI file: {}", e))
        })?;

        // Convert GIFTI data to our SurfaceGeometry
        convert_gifti_to_surface(gifti_data)
    }

    #[cfg(not(feature = "gifti-support"))]
    {
        Err(NeuroSurfError::custom(
            "GIFTI support not enabled. Enable the 'gifti-support' feature".to_string()
        ))
    }
}

/// Write a GIFTI surface file.
pub fn write_gifti_surface<P: AsRef<Path>>(surface: &SurfaceGeometry, path: P) -> Result<()> {
    #[cfg(feature = "gifti-support")]
    {
        // Convert our SurfaceGeometry to GIFTI format
        let gifti_data = convert_surface_to_gifti(surface)?;

        // Write using gifti-rs
        gifti_write(&gifti_data, path).map_err(|e| {
            NeuroSurfError::custom(format!("Failed to write GIFTI file: {}", e))
        })?;

        Ok(())
    }

    #[cfg(not(feature = "gifti-support"))]
    {
        let _ = surface;
        let _ = path;
        Err(NeuroSurfError::custom(
            "GIFTI support not enabled. Enable the 'gifti-support' feature".to_string()
        ))
    }
}

#[cfg(feature = "gifti-support")]
fn convert_gifti_to_surface(gifti_data: Gifti) -> Result<SurfaceGeometry> {
    use ndarray::Array2;

    // Find coordinate and triangle data arrays
    let mut coordinates = None;
    let mut triangles = None;

    for (i, data_array) in gifti_data.data_arrays().enumerate() {
        match data_array.attributes().intent() {
            Intent::Pointset => {
                if coordinates.is_some() {
                    return Err(NeuroSurfError::custom("Multiple coordinate arrays found".to_string()));
                }

                // Convert to ndarray::Array2<f64>
                let data = data_array.data();
                let shape = (data_array.attributes().dim0() as usize, data_array.attributes().dim1() as usize);

                match data_array.attributes().datatype() {
                    DataType::Float32 => {
                        if let Some(float_data) = data.as_float32() {
                            let coords = Array2::from_shape_vec(shape, 
                                float_data.iter().map(|&x| x as f64).collect()
                            ).map_err(|e| NeuroSurfError::custom(format!("Failed to create coordinate array: {}", e)))?;
                            coordinates = Some(coords);
                        }
                    }
                    _ => return Err(NeuroSurfError::custom("Unsupported coordinate data type".to_string())),
                }
            }
            Intent::Triangle => {
                if triangles.is_some() {
                    return Err(NeuroSurfError::custom("Multiple triangle arrays found".to_string()));
                }

                // Convert to ndarray::Array2<usize>
                let data = data_array.data();
                let shape = (data_array.attributes().dim0() as usize, data_array.attributes().dim1() as usize);

                match data_array.attributes().datatype() {
                    DataType::Int32 => {
                        if let Some(int_data) = data.as_int32() {
                            let faces = Array2::from_shape_vec(shape,
                                int_data.iter().map(|&x| x as usize).collect()
                            ).map_err(|e| NeuroSurfError::custom(format!("Failed to create triangle array: {}", e)))?;
                            triangles = Some(faces);
                        }
                    }
                    DataType::Uint32 => {
                        if let Some(uint_data) = data.as_uint32() {
                            let faces = Array2::from_shape_vec(shape,
                                uint_data.iter().map(|&x| x as usize).collect()
                            ).map_err(|e| NeuroSurfError::custom(format!("Failed to create triangle array: {}", e)))?;
                            triangles = Some(faces);
                        }
                    }
                    _ => return Err(NeuroSurfError::custom("Unsupported triangle data type".to_string())),
                }
            }
            _ => {
                // Skip other data arrays for now
                continue;
            }
        }
    }

    let coordinates = coordinates.ok_or_else(|| 
        NeuroSurfError::custom("No coordinate data found in GIFTI file".to_string())
    )?;

    let triangles = triangles.ok_or_else(|| 
        NeuroSurfError::custom("No triangle data found in GIFTI file".to_string())
    )?;

    // Create SurfaceGeometry with default hemisphere and surface type
    // TODO: Extract these from GIFTI metadata if available
    SurfaceGeometry::new(
        coordinates,
        triangles,
        Hemisphere::Left, // Default, should be extracted from metadata
        SurfaceType::White, // Default, should be extracted from metadata
    )
}

#[cfg(feature = "gifti-support")]
fn convert_surface_to_gifti(surface: &SurfaceGeometry) -> Result<Gifti> {
    use gifti::{DataArray, DataArrayAttributes, Encoding, Endianness};

    let mut gifti_data = Gifti::new();

    // Add coordinate data array
    let vertices = surface.vertices()?;
    let vertex_data: Vec<f32> = vertices.iter().map(|&x| x as f32).collect();

    let coord_attrs = DataArrayAttributes::new()
        .with_intent(Intent::Pointset)
        .with_datatype(DataType::Float32)
        .with_dim0(vertices.nrows() as i32)
        .with_dim1(vertices.ncols() as i32)
        .with_encoding(Encoding::GZipBase64Binary)
        .with_endian(Endianness::LittleEndian);

    let coord_array = DataArray::from_vec(vertex_data, coord_attrs)
        .map_err(|e| NeuroSurfError::custom(format!("Failed to create coordinate data array: {}", e)))?;

    gifti_data.add_data_array(coord_array);

    // Add triangle data array
    let faces = surface.faces()?;
    let face_data: Vec<i32> = faces.iter().map(|&x| x as i32).collect();

    let triangle_attrs = DataArrayAttributes::new()
        .with_intent(Intent::Triangle)
        .with_datatype(DataType::Int32)
        .with_dim0(faces.nrows() as i32)
        .with_dim1(faces.ncols() as i32)
        .with_encoding(Encoding::GZipBase64Binary)
        .with_endian(Endianness::LittleEndian);

    let triangle_array = DataArray::from_vec(face_data, triangle_attrs)
        .map_err(|e| NeuroSurfError::custom(format!("Failed to create triangle data array: {}", e)))?;

    gifti_data.add_data_array(triangle_array);

    Ok(gifti_data)
}

