#[cfg(feature = "gifti-support")]
fn convert_surface_to_gifti(surface: &SurfaceGeometry) -> Result<Gifti> {
    use gifti::{DataArray, DataArrayAttributes, Encoding, Endianness, MetaData};

    let mut gifti_data = Gifti::new();

    // Add coordinate data array
    let vertices = surface.vertices()?;
    let vertex_data: Vec<f64> = vertices.iter().map(|&x| x as f64).collect();

    // Create manually using the available constructor
    let coord_attributes = DataArrayAttributes::new(
        DataType::Float32,
        Encoding::GZipBase64Binary,
        Endianness::native(),
        Intent::Pointset,
        vec![vertices.nrows(), vertices.ncols()],
    );

    let coord_array = DataArray {
        attributes: coord_attributes,
        metadata: MetaData::new(),
        data: vertex_data,
    };

    gifti_data.add_data_array(coord_array);

    // Add triangle data array
    let faces = surface.faces()?;
    let face_data: Vec<f64> = faces.iter().map(|&x| x as f64).collect();

    let triangle_attributes = DataArrayAttributes::new(
        DataType::Int32,
        Encoding::GZipBase64Binary,
        Endianness::native(),
        Intent::Triangle,
        vec![faces.nrows(), faces.ncols()],
    );

    let triangle_array = DataArray {
        attributes: triangle_attributes,
        metadata: MetaData::new(),
        data: face_data,
    };

    gifti_data.add_data_array(triangle_array);

    Ok(gifti_data)
}

