    Ok(curvature)
}

impl SurfaceGeometry {
    /// Compute mean curvature for this surface.
    pub fn mean_curvature(&self) -> Result<Array1<f64>> {
        compute_mean_curvature(self)
    }

    /// Compute Gaussian curvature for this surface.
    pub fn gaussian_curvature(&self) -> Result<Array1<f64>> {
        compute_gaussian_curvature(self)
    }

    /// Compute principal curvatures for this surface.
