/// Compute Gaussian curvature for all vertices.
pub fn compute_gaussian_curvature(surface: &SurfaceGeometry) -> Result<Array1<f64>> {
    let vertex_count = surface.vertex_count();
    let vertices = surface.vertices()?;
    let faces = surface.faces()?;

    let mut curvature = Array1::zeros(vertex_count);
    let mut vertex_areas = Array1::zeros(vertex_count);

    // Build vertex-to-faces mapping
    let mut vertex_faces: Vec<Vec<usize>> = vec![Vec::new(); vertex_count];

    for face_idx in 0..faces.nrows() {
        let v0 = faces[[face_idx, 0]];
        let v1 = faces[[face_idx, 1]];
        let v2 = faces[[face_idx, 2]];

        vertex_faces[v0].push(face_idx);
        vertex_faces[v1].push(face_idx);
        vertex_faces[v2].push(face_idx);
    }

    // Compute Gaussian curvature using angle defect method
    for vertex_idx in 0..vertex_count {
        let mut angle_sum = 0.0;
        let mut area = 0.0;

        let vertex_pos = [vertices[[vertex_idx, 0]], vertices[[vertex_idx, 1]], vertices[[vertex_idx, 2]]];

        for &face_idx in &vertex_faces[vertex_idx] {
            let v0 = faces[[face_idx, 0]];
            let v1 = faces[[face_idx, 1]];
            let v2 = faces[[face_idx, 2]];

            // Find which vertex in the face corresponds to our vertex_idx
            let (vertex_in_face, other1, other2) = if v0 == vertex_idx {
                (v0, v1, v2)
            } else if v1 == vertex_idx {
                (v1, v0, v2)
            } else {
                (v2, v0, v1)
            };

            // Get positions of the three vertices
            let p0 = [vertices[[vertex_in_face, 0]], vertices[[vertex_in_face, 1]], vertices[[vertex_in_face, 2]]];
            let p1 = [vertices[[other1, 0]], vertices[[other1, 1]], vertices[[other1, 2]]];
            let p2 = [vertices[[other2, 0]], vertices[[other2, 1]], vertices[[other2, 2]]];

            // Compute vectors from vertex to its neighbors in this face
            let vec1 = [p1[0] - p0[0], p1[1] - p0[1], p1[2] - p0[2]];
            let vec2 = [p2[0] - p0[0], p2[1] - p0[1], p2[2] - p0[2]];

            // Normalize vectors
            let len1 = (vec1[0] * vec1[0] + vec1[1] * vec1[1] + vec1[2] * vec1[2]).sqrt();
            let len2 = (vec2[0] * vec2[0] + vec2[1] * vec2[1] + vec2[2] * vec2[2]).sqrt();

            if len1 > 0.0 && len2 > 0.0 {
                let norm_vec1 = [vec1[0] / len1, vec1[1] / len1, vec1[2] / len1];
                let norm_vec2 = [vec2[0] / len2, vec2[1] / len2, vec2[2] / len2];

                // Compute angle using dot product
                let dot_product = norm_vec1[0] * norm_vec2[0] + norm_vec1[1] * norm_vec2[1] + norm_vec1[2] * norm_vec2[2];
                let dot_clamped = dot_product.clamp(-1.0, 1.0);
                let angle = dot_clamped.acos();

                angle_sum += angle;

                // Add area contribution (1/3 of triangle area)
                let cross = [
                    vec1[1] * vec2[2] - vec1[2] * vec2[1],
                    vec1[2] * vec2[0] - vec1[0] * vec2[2],
                    vec1[0] * vec2[1] - vec1[1] * vec2[0],
                ];
                let triangle_area = 0.5 * (cross[0] * cross[0] + cross[1] * cross[1] + cross[2] * cross[2]).sqrt();
                area += triangle_area / 3.0;
            }
        }

        vertex_areas[vertex_idx] = area;

        if area > 0.0 {
            // Gaussian curvature = (2π - angle_sum) / area
            let angle_defect = 2.0 * std::f64::consts::PI - angle_sum;
            curvature[vertex_idx] = angle_defect / area;
        }
    }

    Ok(curvature)
}

