            let vec1 = [p1[0] - p0[0], p1[1] - p0[1], p1[2] - p0[2]];
            let vec2 = [p2[0] - p0[0], p2[1] - p0[1], p2[2] - p0[2]];

            // Normalize vectors
            let len1 = (vec1[0] * vec1[0] + vec1[1] * vec1[1] + vec1[2] * vec1[2]).sqrt();
            let len2 = (vec2[0] * vec2[0] + vec2[1] * vec2[1] + vec2[2] * vec2[2]).sqrt();

            if len1 > 0.0 && len2 > 0.0 {
                let norm_vec1 = [vec1[0] / len1, vec1[1] / len1, vec1[2] / len1];
                let norm_vec2 = [vec2[0] / len2, vec2[1] / len2, vec2[2] / len2];

                // Compute angle using dot product
                let dot_product = norm_vec1[0] * norm_vec2[0] + norm_vec1[1] * norm_vec2[1] + norm_vec1[2] * norm_vec2[2];
                let dot_clamped = dot_product.clamp(-1.0, 1.0);
                let angle = dot_clamped.acos();

                angle_sum += angle;

                // Add area contribution (1/3 of triangle area)
                let cross = [
                    vec1[1] * vec2[2] - vec1[2] * vec2[1],
                    vec1[2] * vec2[0] - vec1[0] * vec2[2],
                    vec1[0] * vec2[1] - vec1[1] * vec2[0],
                ];
                let triangle_area = 0.5 * (cross[0] * cross[0] + cross[1] * cross[1] + cross[2] * cross[2]).sqrt();
                area += triangle_area / 3.0;
            }
        }

        vertex_areas[vertex_idx] = area;

        if area > 0.0 {
            // Gaussian curvature = (2π - angle_sum) / area
            let angle_defect = 2.0 * std::f64::consts::PI - angle_sum;
            curvature[vertex_idx] = angle_defect / area;
        }
    }

    Ok(curvature)
}

