//! Curvature computation for surface meshes.

use crate::error::{NeuroSurfError, Result};
use crate::geometry::SurfaceGeometry;
use ndarray::Array1;

/// Types of curvature that can be computed.
#[derive(Debug, Clone, Copy, PartialEq)]
pub enum CurvatureType {
    /// Mean curvature
    Mean,
    /// Gaussian curvature
    Gaussian,
    /// Principal curvature (maximum)
    PrincipalMax,
    /// Principal curvature (minimum)
    PrincipalMin,
}

/// Compute curvature values for a surface.
pub fn compute_curvature(surface: &SurfaceGeometry, curvature_type: CurvatureType) -> Result<Array1<f64>> {
    match curvature_type {
        CurvatureType::Mean => compute_mean_curvature(surface),
        CurvatureType::Gaussian => compute_gaussian_curvature(surface),
        CurvatureType::PrincipalMax => compute_principal_curvature_max(surface),
        CurvatureType::PrincipalMin => compute_principal_curvature_min(surface),
    }
}

/// Compute mean curvature for all vertices.
pub fn compute_mean_curvature(surface: &SurfaceGeometry) -> Result<Array1<f64>> {
    let vertex_count = surface.vertex_count();
    let vertices = surface.vertices()?;
    let faces = surface.faces()?;

    let mut curvature = Array1::zeros(vertex_count);
    let mut vertex_areas = Array1::zeros(vertex_count);

    // Build adjacency information
    let mut vertex_neighbors: Vec<Vec<usize>> = vec![Vec::new(); vertex_count];
    let mut vertex_faces: Vec<Vec<usize>> = vec![Vec::new(); vertex_count];

    // Populate adjacency lists
    for face_idx in 0..faces.nrows() {
        let v0 = faces[[face_idx, 0]];
        let v1 = faces[[face_idx, 1]];
        let v2 = faces[[face_idx, 2]];

        // Add neighbors
        vertex_neighbors[v0].push(v1);
        vertex_neighbors[v0].push(v2);
        vertex_neighbors[v1].push(v0);
        vertex_neighbors[v1].push(v2);
        vertex_neighbors[v2].push(v0);
        vertex_neighbors[v2].push(v1);

        // Add face references
        vertex_faces[v0].push(face_idx);
        vertex_faces[v1].push(face_idx);
        vertex_faces[v2].push(face_idx);
    }

    // Remove duplicates and sort
    for neighbors in &mut vertex_neighbors {
        neighbors.sort_unstable();
        neighbors.dedup();
    }

    // Compute vertex areas using the "one-ring" method
    for vertex_idx in 0..vertex_count {
        let mut area = 0.0;

        for &face_idx in &vertex_faces[vertex_idx] {
            let v0 = faces[[face_idx, 0]];
            let v1 = faces[[face_idx, 1]];
            let v2 = faces[[face_idx, 2]];

            // Get vertex coordinates
            let p0 = [vertices[[v0, 0]], vertices[[v0, 1]], vertices[[v0, 2]]];
            let p1 = [vertices[[v1, 0]], vertices[[v1, 1]], vertices[[v1, 2]]];
            let p2 = [vertices[[v2, 0]], vertices[[v2, 1]], vertices[[v2, 2]]];

            // Calculate triangle area using cross product
            let edge1 = [p1[0] - p0[0], p1[1] - p0[1], p1[2] - p0[2]];
            let edge2 = [p2[0] - p0[0], p2[1] - p0[1], p2[2] - p0[2]];

            let cross = [
                edge1[1] * edge2[2] - edge1[2] * edge2[1],
                edge1[2] * edge2[0] - edge1[0] * edge2[2],
                edge1[0] * edge2[1] - edge1[1] * edge2[0],
            ];

            let triangle_area = 0.5 * (cross[0] * cross[0] + cross[1] * cross[1] + cross[2] * cross[2]).sqrt();

            // Add 1/3 of triangle area to this vertex
            area += triangle_area / 3.0;
        }

        vertex_areas[vertex_idx] = area;
    }

    // Compute mean curvature using cotangent weights
    for vertex_idx in 0..vertex_count {
        if vertex_areas[vertex_idx] == 0.0 {
            continue;
        }

        let vertex_pos = [vertices[[vertex_idx, 0]], vertices[[vertex_idx, 1]], vertices[[vertex_idx, 2]]];
        let mut laplacian = [0.0, 0.0, 0.0];
        let mut total_weight = 0.0;

        for &neighbor_idx in &vertex_neighbors[vertex_idx] {
            let neighbor_pos = [vertices[[neighbor_idx, 0]], vertices[[neighbor_idx, 1]], vertices[[neighbor_idx, 2]]];

            // Compute cotangent weight (simplified approach)
            // In a full implementation, we would compute the actual cotangent of adjacent angles
            let edge_vec = [
                neighbor_pos[0] - vertex_pos[0],
                neighbor_pos[1] - vertex_pos[1],
                neighbor_pos[2] - vertex_pos[2],
            ];

            let edge_length = (edge_vec[0] * edge_vec[0] + edge_vec[1] * edge_vec[1] + edge_vec[2] * edge_vec[2]).sqrt();

            if edge_length > 0.0 {
                // Simplified uniform weight (for proper cotangent weights, we'd need angle calculations)
                let weight = 1.0 / edge_length;
                total_weight += weight;

                laplacian[0] += weight * edge_vec[0];
                laplacian[1] += weight * edge_vec[1];
                laplacian[2] += weight * edge_vec[2];
            }
        }

        if total_weight > 0.0 {
            // Normalize by total weight and vertex area
            let laplacian_magnitude = (laplacian[0] * laplacian[0] + laplacian[1] * laplacian[1] + laplacian[2] * laplacian[2]).sqrt();
            curvature[vertex_idx] = laplacian_magnitude / (2.0 * vertex_areas[vertex_idx]);
        }
    }

    Ok(curvature)
}

