fn find_mode(values: &[f64]) -> f64 {
    if values.is_empty() {
        return 0.0;
    }

    // Convert to integers for counting (multiply by 1000 for precision)
    let mut int_values: Vec<(i64, f64)> = values.iter()
        .map(|&v| ((v * 1000.0).round() as i64, v))
        .collect();

    // Sort to group identical values
    int_values.sort_by_key(|(i, _)| *i);

    let mut max_count = 0;
    let mut mode_value = 0.0;
    let mut current_count = 1;
    let mut current_int = int_values[0].0;
    let mut current_original = int_values[0].1;

    for i in 1..int_values.len() {
        if int_values[i].0 == current_int {
            current_count += 1;
        } else {
            if current_count > max_count {
                max_count = current_count;
                mode_value = current_original;
            }
            current_count = 1;
            current_int = int_values[i].0;
            current_original = int_values[i].1;
        }
    }

    // Check the last group
    if current_count > max_count {
        mode_value = current_original;
    }

    mode_value
}

