//! Volume to surface mapping algorithms.

use crate::error::{NeuroSurfError, Result};
use crate::geometry::SurfaceGeometry;
use crate::surface::NeuroSurface;
use ndarray::{Array1, Array3};
use nalgebra::Point3;

/// Volume-to-surface mapping strategy
#[derive(Debug, Clone, Copy, PartialEq)]
pub enum MappingFunction {
    /// Average of nearby voxels (default)
    Average,
    /// Nearest neighbor value
    NearestNeighbor,
    /// Most frequent value among nearby voxels
    Mode,
}

/// Parameters for volume-to-surface mapping
#[derive(Debug, Clone)]
pub struct VolToSurfParams {
    /// Mapping function to use
    pub mapping_function: MappingFunction,
    /// Number of nearest neighbors to consider
    pub knn: usize,
    /// Bandwidth of the smoothing kernel for average mapping
    pub sigma: f64,
    /// Maximum distance threshold for valid mapping
    pub distance_threshold: f64,
}

impl Default for VolToSurfParams {
    fn default() -> Self {
        Self {
            mapping_function: MappingFunction::Average,
            knn: 6,
            sigma: 8.0,
            distance_threshold: 16.0, // 2 * sigma
        }
    }
}

/// 3D volume representation for mapping
#[derive(Debug, Clone)]
pub struct Volume3D {
    /// Volume data
    pub data: Array3<f64>,
    /// Voxel dimensions (spacing)
    pub voxel_size: [f64; 3],
    /// Volume origin in world coordinates
    pub origin: Point3<f64>,
}

impl Volume3D {
    /// Create a new volume
    pub fn new(data: Array3<f64>, voxel_size: [f64; 3], origin: Point3<f64>) -> Self {
        Self {
            data,
            voxel_size,
            origin,
        }
    }

    /// Get dimensions of the volume
    pub fn dims(&self) -> [usize; 3] {
        let shape = self.data.dim();
        [shape.0, shape.1, shape.2]
    }

    /// Convert voxel indices to world coordinates
    pub fn index_to_coord(&self, i: usize, j: usize, k: usize) -> Point3<f64> {
        Point3::new(
            self.origin.x + i as f64 * self.voxel_size[0],
            self.origin.y + j as f64 * self.voxel_size[1],
            self.origin.z + k as f64 * self.voxel_size[2],
        )
    }

    /// Get all non-zero voxel coordinates and values
    pub fn get_nonzero_voxels(&self) -> Vec<(Point3<f64>, f64)> {
        let mut voxels = Vec::new();
        let dims = self.dims();

        for i in 0..dims[0] {
            for j in 0..dims[1] {
                for k in 0..dims[2] {
                    let value = self.data[[i, j, k]];
                    if value != 0.0 {
                        let coord = self.index_to_coord(i, j, k);
                        voxels.push((coord, value));
                    }
                }
            }
        }

        voxels
    }
}

/// Map values from a 3D volume to a surface
///
/// This function maps values from a 3D volume to a surface representation using
/// the average position between white matter (inner) and pial (outer) surfaces.
///
/// # Arguments
/// 
/// * `surf_wm` - White matter (inner) surface geometry
/// * `surf_pial` - Pial (outer) surface geometry  
/// * `volume` - 3D volume to map from
/// * `params` - Mapping parameters
/// 
/// # Returns
/// 
/// A NeuroSurface with mapped values from the volume
pub fn vol_to_surf(
    surf_wm: &SurfaceGeometry,
    surf_pial: &SurfaceGeometry,
    volume: &Volume3D,
    params: &VolToSurfParams,
) -> Result<NeuroSurface> {
    // Get vertices from both surfaces
    let wm_vertices = surf_wm.vertices()?;
    let pial_vertices = surf_pial.vertices()?;

    // Check that surfaces have same number of vertices
    if wm_vertices.nrows() != pial_vertices.nrows() {
        return Err(NeuroSurfError::custom(
            "White matter and pial surfaces must have the same number of vertices".to_string()
        ));
    }

    let num_vertices = wm_vertices.nrows();

    // Calculate average vertex positions (midpoint between wm and pial)
    let mut avg_vertices = Vec::with_capacity(num_vertices);
    for i in 0..num_vertices {
        let wm_vertex = Point3::new(wm_vertices[[i, 0]], wm_vertices[[i, 1]], wm_vertices[[i, 2]]);
        let pial_vertex = Point3::new(pial_vertices[[i, 0]], pial_vertices[[i, 1]], pial_vertices[[i, 2]]);
        let avg_vertex = Point3::new(
            (wm_vertex.x + pial_vertex.x) / 2.0,
            (wm_vertex.y + pial_vertex.y) / 2.0,
            (wm_vertex.z + pial_vertex.z) / 2.0,
        );
        avg_vertices.push(avg_vertex);
    }

    // Get non-zero voxels from volume
    let voxels = volume.get_nonzero_voxels();
    if voxels.is_empty() {
        return Err(NeuroSurfError::custom("Volume contains no non-zero voxels".to_string()));
    }

    // Map each vertex to volume values
    let mut mapped_values = Vec::with_capacity(num_vertices);

    for vertex_pos in &avg_vertices {
        let mapped_value = map_vertex_to_volume(vertex_pos, &voxels, params)?;
        mapped_values.push(mapped_value);
    }

    // Create indices (all vertices)
    let indices: Vec<usize> = (0..num_vertices).collect();
    let data = Array1::from_vec(mapped_values);

    // Create NeuroSurface using white matter geometry as base
    NeuroSurface::new(surf_wm.clone(), indices, data)
}

/// Map a single vertex position to volume values
fn map_vertex_to_volume(
    vertex_pos: &Point3<f64>,
    voxels: &[(Point3<f64>, f64)],
    params: &VolToSurfParams,
) -> Result<f64> {
    // Find k nearest neighbors
    let mut distances: Vec<(f64, f64)> = voxels.iter()
        .map(|(pos, value)| {
            let dist = (vertex_pos - pos).norm();
            (dist, *value)
        })
        .collect();

    // Sort by distance and take k nearest
    distances.sort_by(|a, b| a.0.partial_cmp(&b.0).unwrap());
    distances.truncate(params.knn);

    // Filter by distance threshold
    let valid_neighbors: Vec<(f64, f64)> = distances.into_iter()
        .filter(|(dist, _)| *dist < params.distance_threshold)
        .collect();

    if valid_neighbors.is_empty() {
        return Ok(0.0); // No valid neighbors found
    }

    // Apply mapping function
    match params.mapping_function {
        MappingFunction::Average => {
            // Weighted average using Gaussian kernel
            let mut weighted_sum = 0.0;
            let mut weight_sum = 0.0;

            for (dist, value) in &valid_neighbors {
                let weight = gaussian_kernel(*dist, params.sigma);
                weighted_sum += weight * value;
                weight_sum += weight;
            }

            if weight_sum > 0.0 {
                Ok(weighted_sum / weight_sum)
            } else {
                Ok(0.0)
            }
        }
        MappingFunction::NearestNeighbor => {
            // Return value of nearest neighbor
            Ok(valid_neighbors[0].1)
        }
        MappingFunction::Mode => {
            // Find most frequent value
            let values: Vec<f64> = valid_neighbors.iter().map(|(_, v)| *v).collect();
            Ok(find_mode(&values))
        }
    }
}

/// Gaussian kernel function for weighted averaging
fn gaussian_kernel(distance: f64, sigma: f64) -> f64 {
    (-distance.powi(2) / (2.0 * sigma.powi(2))).exp()
}

/// Find the mode (most frequent value) in a vector
fn find_mode(values: &[f64]) -> f64 {
    use std::collections::HashMap;

    if values.is_empty() {
        return 0.0;
    }

    // Count occurrences (with some tolerance for floating point comparison)
    let mut counts = HashMap::new();
    for &value in values {
        // Round to avoid floating point precision issues
        let rounded = (value * 1000.0).round() / 1000.0;
        *counts.entry(rounded).or_insert(0) += 1;
    }

    // Find most frequent value
    counts.into_iter()
        .max_by_key(|(_, count)| *count)
        .map(|(value, _)| value)
        .unwrap_or(0.0)
}

#[cfg(test)]
mod tests {
    use super::*;
    use ndarray::array;
    use crate::geometry::{Hemisphere, SurfaceType};

    #[test]
    fn test_volume_creation() {
        let data = Array3::zeros((10, 10, 10));
        let voxel_size = [1.0, 1.0, 1.0];
        let origin = Point3::new(0.0, 0.0, 0.0);

        let volume = Volume3D::new(data, voxel_size, origin);
        assert_eq!(volume.dims(), [10, 10, 10]);
    }

    #[test]
    fn test_gaussian_kernel() {
        let weight1 = gaussian_kernel(0.0, 1.0);
        let weight2 = gaussian_kernel(1.0, 1.0);
        let weight3 = gaussian_kernel(2.0, 1.0);

        assert!(weight1 > weight2);
        assert!(weight2 > weight3);
        assert!((weight1 - 1.0).abs() < 1e-10);
